package com.kalyani.car_rental_backend.review.entity;import com.kalyani.car_rental_backend.booking.entity.Booking;import com.kalyani.car_rental_backend.user.entity.User;import jakarta.persistence.*;import java.time.LocalDateTime;
@Entity @Table(name="reviews",uniqueConstraints=@UniqueConstraint(name="uk_review_booking",columnNames="booking_id"))public class Review{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@OneToOne(optional=false)private Booking booking;@ManyToOne(optional=false)private User user;@Column(nullable=false)private int rating;@Column(length=1500)private String comment;@Column(nullable=false,updatable=false)private LocalDateTime createdAt;@PrePersist void pre(){createdAt=LocalDateTime.now();}public Long getId(){return id;}public Booking getBooking(){return booking;}public void setBooking(Booking v){booking=v;}public User getUser(){return user;}public void setUser(User v){user=v;}public int getRating(){return rating;}public void setRating(int v){rating=v;}public String getComment(){return comment;}public void setComment(String v){comment=v;}public LocalDateTime getCreatedAt(){return createdAt;}}
